function ariaLabels() {
  var headerContainer = document.getElementById("headerContainer");
  headerContainer.setAttribute("role", "banner");
  var navigationContainer = document.getElementById("navigationContainer");
  if (navigationContainer) {
    navigationContainer.setAttribute("role", "navigation");
    navigationContainer.setAttribute("aria-label", "Main menu");
  }
  var navSecondary = document.getElementById("navSecondary");
  if (navSecondary) {
    navSecondary.setAttribute("aria-label", "Secondary");
  }
  var lastUpdated = document.getElementById("lastUpdated");
  if (lastUpdated) {
    lastUpdated.setAttribute("aria-label", "Last updated");
  }
  var breadcrumb = document.getElementById("breadCrumb");
  if (breadcrumb) {
    breadcrumb.setAttribute("aria-label", "Previous page:");
    var lastItem = breadcrumb.querySelector("li:last-of-type");
    lastItem.setAttribute("aria-current", "page");
  }
  var top = document.getElementById("top");
  if (top) {
    top.setAttribute("aria-label", "Skip to content");
  }
  var betaUserTesting = document.getElementById("beta-user-testing");
  if (betaUserTesting) {
    betaUserTesting.setAttribute("aria-label", "Beta feedback");
  }
  var feedback = document.getElementById("feedback");
  if (feedback) {
    feedback.setAttribute("aria-label", "Is this page useful");
    var feedbackMessage = document.querySelector("p.feedback-message");
  }
  var pagination = document.getElementById("pagination");
  if (pagination) {
    pagination.setAttribute("role", "navigation");
    pagination.setAttribute("aria-label", "Pagination Navigation");
  }
  var multistepNav = document.getElementById("multistepNav");
  if (multistepNav) {
    multistepNav.setAttribute("role", "navigation");
    multistepNav.setAttribute("aria-label", "Secondary");
  }
  var sideBar = document.getElementById("sideBar");
  if (sideBar) {
    sideBar.setAttribute("role", "complementary");
  }
  var search = document.querySelector("form.gsc-search-box");
  if (search) {
    search.setAttribute("aria-label", "Primary");
    search.setAttribute("role", "search");
  }
  var localsearch = document.querySelector("form.gsc-search-box");
  if (localsearch) {
    localsearch.setAttribute("aria-label", "Secondary");
    localsearch.setAttribute("role", "search");
  }
  var gscSearch = document.querySelector("form.gsc-search-box");
  if (gscSearch) {
    gscSearch.setAttribute("role", "search");
  }
  var asideBottom = document.querySelector("#asideBottom");
  if (asideBottom) {
    asideBottom.setAttribute("role", "complementary");
  }
  var sidebarAside = document.querySelector("#sidebarAside");
  if (sidebarAside) {
    sidebarAside.setAttribute("role", "complementary");
  }
  var aside = document.querySelector("#contentAside");
  if (aside) {
    aside.setAttribute("role", "complementary");
  }
  var micrositeHomepage = document.querySelector(".columnbetacontentpage.column1");
  var callout = document.querySelectorAll(".callout");
  if (callout) {
    callout.forEach(function (box, index) {
      box.setAttribute("id", "callout-".concat(index));
      box.setAttribute("role", "note");
      if (micrositeHomepage) {
        box.setAttribute("role", "region");
      }
    });
  }
  var boxNoteInformation = document.querySelectorAll(".callout--information");
  if (boxNoteInformation) {
    boxNoteInformation.forEach(function (box, index) {
      box.setAttribute("id", "callout-information-".concat(index));
      box.setAttribute("role", "note");
      box.setAttribute("aria-label", "Information");
      if (micrositeHomepage) {
        box.setAttribute("role", "region");
      }
    });
  }
  var boxNoteWarning = document.querySelectorAll(".callout--warning");
  if (boxNoteWarning) {
    boxNoteWarning.forEach(function (box, index) {
      box.setAttribute("id", "callout-warning-".concat(index));
      box.setAttribute("role", "note");
      box.setAttribute("aria-label", "Warning");
    });
  }
  var boxNoteSurvey = document.querySelectorAll(".callout--survey");
  if (boxNoteSurvey) {
    boxNoteSurvey.forEach(function (box, index) {
      box.setAttribute("id", "callout-survey-".concat(index));
      box.setAttribute("role", "note");
      box.setAttribute("aria-label", "Survey");
    });
  }
  var contentsList = document.querySelector(".hse-contents-list");
  if (contentsList) {
    contentsList.setAttribute("aria-label", "Contents");
  }
}

