function fileTypeFunction() {
  // Select anchors from #page-contents and .hse-browse-section__list
  var anchors = document.querySelectorAll('#page-contents a, .hse-browse-section__list a');

  // Use a mapping for file types
  var fileTypes = {
    pdf: {
      shortText: 'PDF',
      longText: 'Portable Document Format'
    },
    doc: {
      shortText: '.doc',
      longText: 'Microsoft Word document'
    },
    docx: {
      shortText: '.docx',
      longText: 'Microsoft Word document'
    },
    xls: {
      shortText: '.xls',
      longText: 'Microsoft Excel spreadsheet'
    },
    xlsx: {
      shortText: '.xlsx',
      longText: 'Microsoft Excel spreadsheet'
    },
    ppt: {
      shortText: '.ppt',
      longText: 'Microsoft PowerPoint presentation'
    },
    pptx: {
      shortText: '.pptx',
      longText: 'Microsoft PowerPoint presentation'
    },
    pps: {
      shortText: '.pps',
      longText: 'Microsoft PowerPoint presentation'
    },
    zip: {
      shortText: '.zip',
      longText: 'Zip file'
    },
    mp3: {
      shortText: '.mp3',
      longText: 'MP3 audio file'
    }
  };
  anchors.forEach(function (elem) {
    var path = elem.href;
    var extension = path.split('.').pop();

    // Get the file type description if exists
    var fileType = fileTypes[extension];

    // If a matching file type is found, append the description
    if (fileType) {
      var description = "\n                <span class=\"fileType\">\n                    <span> (<abbr title=\"".concat(fileType.longText, "\">").concat(fileType.shortText, "</abbr>)</span>\n                </span>");
      elem.innerHTML += description; // Append description
    }
  });
}

