function footnoteAbbr() {
  var container = document.getElementById('contentContainer');

  // exit early if container doesn't exist
  if (!container) return;
  var accronym = container.querySelectorAll('acronym, abbr');
  var listItems = '';

  // build definition list items
  accronym.forEach(function (item) {
    listItems += "<dt>".concat(item.innerText, "</dt><dd>").concat(item.title, "</dd>");
  });
  var html = "\n    <h2 class=\"hideFromScreen footnotes\">Glossary of abbreviations/acronyms on this page</h2>\n    <dl class=\"hideFromScreen\">\n        ".concat(listItems, "\n    </dl>");
  if (listItems.length > 0) {
    container.insertAdjacentHTML('beforeend', html);
  }
}

