function footnoteLinks() {
  var container = document.getElementById('pageContainer');
  var links = document.querySelectorAll("#contentContainer a:not([href^='javascript:']):not([href^='mailto:']):not(:empty):not([href^='#'])");
  var listItems = [];
  var count = 0;
  links.forEach(function (item) {
    count++;

    // build list items
    listItems += "<li class=\"hse-footnotes__list-item\"><span class=\"hse-footnotes__list-item-title\">".concat(item.text, "</span><span class=\"hse-footnotes__list-item-url\">").concat(item.href, "</span></li>\n        ");

    // add counter to each link
    item.insertAdjacentHTML('afterend', '<sup class="hideFromScreen">[' + count + ']</sup>');
  });
  var html = "\n    <div class=\"hse-footnotes\">\n    <h2 class=\"hideFromScreen footnotes\">Link URLs in this page</h2>\n    <ol class=\"hse-footnotes__list hideFromScreen\">\n        ".concat(listItems, "\n    </ol>\n    </div>");
  if (listItems.length > 0) {
    container.insertAdjacentHTML('beforeend', html);
  }
}

