function htmlFormsAntiSpam() {
  var accordionFormButton = document.querySelector('.btn-form');
  if (!accordionFormButton) {
    return;
  }
  // Event listener for form button

  accordionFormButton.addEventListener('click', insertForm);
  function insertForm() {
    var formButton = document.querySelector('.btn-form');
    if (!formButton) {
      return;
    }
    var formContainer = document.querySelector('.form-content');
    var content = formContainer.dataset.content;

    // get html form
    fetch("/assets/ajax/forms/".concat(content, ".htm")).then(function (response) {
      return response.text();
    }).then(function (html) {
      // form html string
      var formhtml = html;
      formContainer.innerHTML = formhtml;
    })["catch"](function () {
      console.error("No such file: ".concat(content));
    });

    // scroll to content
    formContainer.scrollIntoView({
      behavior: "smooth",
      block: "start"
    });

    // remove form button
    var contentContainer = document.querySelector('#contentContainer');
    contentContainer.removeChild(accordionFormButton);
  }
}

