function informationBanner() {
  var container = document.getElementById('information-banner');
  if (!container) {
    return;
  }
  var inner = container.querySelector('.hse-information-banner__inner');
  var content = container.dataset.content;
  if (content) {
    var firstPath = window.location.pathname.split('/')[1];
    var secondPath = window.location.pathname.split('/')[2];
    var thirdPath = window.location.pathname.split('/')[3];

    //console.log(firstPath);
    //console.log(secondPath);
    //console.log(thirdPath);

    if (firstPath === 'website') {
      fetch("/".concat(firstPath, "/").concat(secondPath, "/").concat(thirdPath, "/assets/ajax/").concat(content)).then(function (response) {
        return response.json();
      }).then(function (data) {
        inner.innerHTML = data.message;
        container.setAttribute('aria-label', data.ariaLabel);
      })["catch"](function () {
        console.error("No such file: ".concat(content));
      });
    } else {
      fetch("/assets/ajax/".concat(content)).then(function (response) {
        return response.json();
      }).then(function (data) {
        inner.innerHTML = data.message;
        container.setAttribute('aria-label', data.ariaLabel);
      })["catch"](function () {
        console.error("No such file: ".concat(content));
      });
    }
  } else {
    return;
  }
}

