function topTasks() {
  var multiStep = document.querySelectorAll("ol.multistep a");
  if (multiStep.length <= 0) {
    return;
  }
  var path = window.location.pathname;
  var pathAnchor = window.location.pathname + "#article";
  var url = path ? path.split(/[\\\/]/).pop() : "index.htm";
  var urlAnchor = pathAnchor ? pathAnchor.split(/[\\\/]/).pop() : "index.htm";
  multiStep.forEach(function (step) {
    var parent = step.closest("li");
    var href = step.href.split(/[\\\/]/).pop();
    if (href === url || href === urlAnchor) {
      if (!parent.classList.contains("step-detail")) {
        parent.innerHTML = step.innerHTML;
      }
    }
  });
}

